#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e5+5;
int n,m,res=0,fa[MAXN];
struct node{int u,v,w;}a[MAXN];
bool cmp(const node&e1,const node&e2){return e1.w<e2.w;}
int find(int x){return ((fa[x]==x)?(x):(fa[x]=find(fa[x])));}
bool same(int x,int y){
    int X=find(x),Y=find(y);
    if(X!=Y){fa[X]=Y;return true;}return false;
}void Kruskal(){
    sort(a,a+m,cmp);
    for(int i=0;i<m;++i){
        if(same(a[i].u,a[i].v)){
            res=max(res,a[i].w);
        }
    }
}int main(void){	
	scanf("%d%d",&n,&m);
    for(int i=0,x,y,w;i<m;++i)scanf("%d%d%d",&x,&y,&w),a[i]={x,y,w};
	for(int i=0;i<n;++i)fa[i]=i;
    Kruskal();printf("%d %d",n-1,res);
    return false;
}
